import{c as n,Q as s,j as a,m as o}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"维度机制:下界缩放、传送门与末地","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/25-维度机制-下界缩放传送门与末地.md","filePath":"minecraftLearning/25-维度机制-下界缩放传送门与末地.md","lastUpdated":1781677803000}'),e={name:"minecraftLearning/25-维度机制-下界缩放传送门与末地.md"};function r(d,t,p,l,i,c){return s(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="维度机制-下界缩放、传送门与末地" tabindex="-1">维度机制:下界缩放、传送门与末地 <a class="header-anchor" href="#维度机制-下界缩放、传送门与末地" aria-label="Permalink to &quot;维度机制:下界缩放、传送门与末地&quot;">​</a></h1><p>第 11 篇说过&quot;维度是一个个独立的世界,各自有独立的 chunk 存储&quot;。那一篇是把维度当成容器一笔带过的。这一篇把容器打开,讲清楚三件容易被当成&quot;魔法&quot;的事:<strong>为什么下界走得快、传送门凭什么知道把你送到哪、末地那一堆传送门各自是干嘛的</strong>。</p><blockquote><p>一句话先记住:<strong>维度不是&quot;另一张地图&quot;,而是一组由 <code>DimensionType</code> 描述的环境参数 + 一份独立的世界生成配置 + 一份独立的存档。维度之间唯一的连接是传送门,而传送门干的活本质上只是&quot;按比例换算坐标 + 在附近找/建一个出口&quot;。</strong></p></blockquote><hr><h2 id="一、维度由两层定义-类型-环境-生成-地形" tabindex="-1">一、维度由两层定义:类型(环境)+ 生成(地形) <a class="header-anchor" href="#一、维度由两层定义-类型-环境-生成-地形" aria-label="Permalink to &quot;一、维度由两层定义:类型(环境)+ 生成(地形)&quot;">​</a></h2><p>很多人以为&quot;主世界 / 下界 / 末地&quot;是写死在引擎里的三个东西。1.16 之后<strong>完全不是</strong>——一个维度是数据驱动的,由两块拼出来(呼应第 11 篇动态注册表、第 16 篇世界生成):</p><table tabindex="0"><thead><tr><th>层</th><th>注册表</th><th>管什么</th></tr></thead><tbody><tr><td><strong>维度类型 DimensionType</strong></td><td><code>dimension_type</code></td><td>环境参数:高度范围、坐标缩放、有没有天空、环境光、能不能放床/床会不会炸、岩浆流速、出怪光照等</td></tr><tr><td><strong>维度本身 LevelStem / dimension</strong></td><td><code>dimension</code></td><td>把一个 DimensionType 和一套世界生成器(noise settings / biome source)绑在一起</td></tr></tbody></table><p>也就是说:<strong>环境规则</strong>和<strong>地形怎么长</strong>是分开配置的。你可以写一个 JSON 给&quot;主世界地形 + 下界环境参数&quot;的缝合怪维度,引擎照跑。</p><h3 id="dimensiontype-里最关键的几个字段" tabindex="-1">DimensionType 里最关键的几个字段 <a class="header-anchor" href="#dimensiontype-里最关键的几个字段" aria-label="Permalink to &quot;DimensionType 里最关键的几个字段&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;min_y&quot;: -64, &quot;height&quot;: 384,</span><span>         // 世界高度范围(主世界 1.18 后)</span></span>
<span class="line"><span>  &quot;coordinate_scale&quot;: 1.0,</span><span>             // 坐标缩放,关键!</span></span>
<span class="line"><span>  &quot;has_ceiling&quot;: false,</span><span>                // 下界为 true:有基岩天花板</span></span>
<span class="line"><span>  &quot;has_skylight&quot;: true,</span><span>                // 下界/末地为 false:没有天空光</span></span>
<span class="line"><span>  &quot;ambient_light&quot;: 0.0,</span><span>                // 环境光底噪,下界 0.1</span></span>
<span class="line"><span>  &quot;bed_works&quot;: true,</span><span>                   // 下界/末地 false → 床会爆炸</span></span>
<span class="line"><span>  &quot;respawn_anchor_works&quot;: false,</span><span>       // 下界专属重生方式</span></span>
<span class="line"><span>  &quot;ultrawarm&quot;: false,</span><span>                  // 下界 true:水会蒸发、岩浆流得快</span></span>
<span class="line"><span>  &quot;natural&quot;: true,</span><span>                     // 末地/下界 false:不能用床、指南针/时钟乱转</span></span>
<span class="line"><span>  &quot;logical_height&quot;: 256</span><span>                // 传送门和区块加载能到的逻辑高度上限</span></span>
<span class="line"><span>}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>维度</th><th>min_y / height</th><th>coordinate_scale</th><th>skylight</th><th>ceiling</th><th>ultrawarm</th></tr></thead><tbody><tr><td>主世界</td><td>-64 / 384</td><td><strong>1.0</strong></td><td>有</td><td>无</td><td>否</td></tr><tr><td>下界</td><td>0 / 256</td><td><strong>8.0</strong></td><td>无</td><td>有(基岩顶)</td><td>是(水蒸发)</td></tr><tr><td>末地</td><td>0 / 256</td><td>1.0</td><td>无</td><td>无</td><td>否</td></tr></tbody></table><p>那个 <code>coordinate_scale = 8.0</code> 就是下面一切的根源。</p><hr><h2 id="二、下界-8-1-不是-下界更小-是坐标换算" tabindex="-1">二、下界 8:1:不是&quot;下界更小&quot;,是坐标换算 <a class="header-anchor" href="#二、下界-8-1-不是-下界更小-是坐标换算" aria-label="Permalink to &quot;二、下界 8:1:不是&quot;下界更小&quot;,是坐标换算&quot;">​</a></h2><p>最经典的反直觉点:<strong>主世界走 1 格,等于在下界走 8 格。</strong></p><p>注意它的实现位置——缩放是写在 <code>DimensionType.coordinate_scale</code> 上的,<strong>主世界 1.0、下界 8.0</strong>。换算发生在<strong>跨维度传送的那一刻</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进下界:  nether.x = overworld.x / 8     (用两者 scale 的比值 8.0/1.0)</span></span>
<span class="line"><span>出下界:  overworld.x = nether.x * 8</span></span>
<span class="line"><span>y 坐标不缩放,直接搬过去</span></span></code></pre></div><p>所以&quot;下界更小&quot;是个错觉。下界的方块和主世界一样大,只是<strong>它覆盖的主世界范围被压缩了 8 倍</strong>:你在下界铺一条 100 格的冰道,对应主世界 800 格。这就是<strong>下界高速路</strong>的全部原理——拿 1:8 的换算比,在下界跑短途换主世界长途。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主世界  A(0,0) ───────── 800 格 ───────── B(800,0)</span></span>
<span class="line"><span>                  ↕ 传送(/8)              ↕ 传送(/8)</span></span>
<span class="line"><span>下界    a(0,0) ── 100 格 ── b(100,0)</span></span></code></pre></div><p><strong>踩坑:</strong> 正因为是&quot;传送时换算 + 附近找门&quot;,1:8 不是精确双射。多个主世界传送门可能落进下界的同一片搜索范围,于是出现&quot;两个主世界门共用一个下界门&quot;&quot;回来时出错地方&quot;的经典配对错乱(见下一节)。手工把每对门的坐标按 /8 对齐,才能稳定一对一。</p><hr><h2 id="三、传送门-一段-换算坐标-找门或建门-的算法" tabindex="-1">三、传送门:一段&quot;换算坐标 + 找门或建门&quot;的算法 <a class="header-anchor" href="#三、传送门-一段-换算坐标-找门或建门-的算法" aria-label="Permalink to &quot;三、传送门:一段&quot;换算坐标 + 找门或建门&quot;的算法&quot;">​</a></h2><p>站进激活的紫色传送门,客户端会有几秒读条,服务端这几秒在干一件具体的事(由 <code>PortalForcer</code> 负责),逻辑大致是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 取玩家当前坐标 (x,y,z),按目标维度 scale 换算:</span></span>
<span class="line"><span>     若去往 scale 更大的维度(主世界→下界)→ 坐标 / 8</span></span>
<span class="line"><span>     反之(下界→主世界)→ 坐标 * 8</span></span>
<span class="line"><span>2. 在换算后的目标坐标周围一个搜索半径内(下界默认 128,主世界更大),</span></span>
<span class="line"><span>   查找已存在的下界传送门方块(缓存 + 扫描)</span></span>
<span class="line"><span>3. 找到 → 把玩家放到那个门,传送结束</span></span>
<span class="line"><span>4. 没找到 → 在目标坐标附近找一块合适的空间,</span></span>
<span class="line"><span>   现场用黑曜石 + 传送门方块「凭空建一个新门」(portal forcer),再放人</span></span></code></pre></div><p>几个由此推出的真相:</p><ul><li><strong>门会&quot;配错&quot;,是算法的必然而非 bug。</strong> 第 4 步&quot;没找到就新建&quot;意味着:你在主世界建了 A、B 两个门,如果它们 /8 后落进下界的同一搜索半径,B 进去时会找到 A 已经建好的下界门 → 出来在错的地方。</li><li><strong>想要稳定的一对一</strong>:自己在下界手动建门,并让它的坐标 ≈ 主世界门坐标 / 8(y 自定),让算法第 2 步&quot;恰好找到你建的那个&quot;,就不会乱跳。</li><li><strong>门是按一组「门框 + 内部传送门方块」识别的</strong>,新建时引擎会找一块能塞下门框的空间,所以有时你会发现下界半空中莫名多出一个平台门——那是 portal forcer 没找到地面、就近造出来的。</li></ul><p>下界传送门用<strong>黑曜石框 + 打火石点燃</strong>;末地传送门是另一套(下面讲),两者机制不同。</p><hr><h2 id="四、末地-三种-门-各管一段路" tabindex="-1">四、末地:三种&quot;门&quot;各管一段路 <a class="header-anchor" href="#四、末地-三种-门-各管一段路" aria-label="Permalink to &quot;四、末地:三种&quot;门&quot;各管一段路&quot;">​</a></h2><p>末地最容易把人绕晕,因为它一口气有三种传送结构,名字都带 portal,但职责完全不同:</p><table tabindex="0"><thead><tr><th>结构</th><th>长什么样</th><th>作用</th></tr></thead><tbody><tr><td><strong>末地传送门 End Portal</strong>(主世界要塞里)</td><td>12 个末影之眼填满的门框</td><td>主世界 → 末地主岛,<strong>单向入口</strong></td></tr><tr><td><strong>返回传送门 Exit Portal</strong>(末地主岛中心)</td><td>杀龙后激活的基岩结构,中间一颗龙蛋</td><td>末地主岛 → 主世界出生点,<strong>回家</strong></td></tr><tr><td><strong>末地折跃门 End Gateway</strong>(主岛外缘)</td><td>悬空的小型基岩结构,一个发光点</td><td>主岛 → 外岛(远处),<strong>去刷鞘翅/紫颂果</strong></td></tr></tbody></table><p>机制要点:</p><ul><li><strong>进末地是&quot;造主岛 + 放龙&quot;</strong>:第一次有人进入末地维度时,世界生成器在主岛上摆好黑曜石柱、末影水晶,并 spawn 末影龙(它是一个有复杂 BlockState/碰撞与多段 AI 的 Boss 实体,呼应第 06 篇)。</li><li><strong>杀龙激活 Exit Portal</strong>:龙死亡触发返回传送门生成,站上去回主世界。<strong>首次</strong>杀龙还会在主岛边缘生成第一个 End Gateway。</li><li><strong>End Gateway 是&quot;定点跳跃&quot;</strong>:每个折跃门绑定一个目标坐标(主岛外约 1000 格的外岛区),踩进去就被弹射过去;它和下界门那种&quot;按比例换算 + 搜索&quot;完全不同,是<strong>预设目标的硬传送</strong>。</li></ul><blockquote><p>反直觉:末地的&quot;外岛&quot;理论上无限延伸,但你<strong>只能靠折跃门跳过去</strong>——主岛和外岛之间是一片虚空,没有连续地形,所以末地是&quot;主岛 + 一圈靠 gateway 连接的孤岛群&quot;,不是一张连续大地图。</p></blockquote><hr><h2 id="五、维度之间-什么共享、什么不共享" tabindex="-1">五、维度之间,什么共享、什么不共享 <a class="header-anchor" href="#五、维度之间-什么共享、什么不共享" aria-label="Permalink to &quot;五、维度之间,什么共享、什么不共享&quot;">​</a></h2><p>这是理解维度模型的最后一块,也是最容易想当然的地方:</p><table tabindex="0"><thead><tr><th>东西</th><th>跨维度?</th><th>说明</th></tr></thead><tbody><tr><td>玩家背包 / 经验</td><td>✅ 跟着玩家走</td><td>玩家实体本身被搬到目标维度</td></tr><tr><td>实体(怪物/掉落物/矿车)</td><td>❌ 不能自由穿越</td><td>必须<strong>显式传送</strong>(走门、指令);各维度的实体各存各的</td></tr><tr><td>chunk / 方块</td><td>❌ 完全独立</td><td>各维度独立存储:<code>DIM-1/</code>(下界)、<code>DIM1/</code>(末地),各自一套 region 文件(呼应第 07 篇)</td></tr><tr><td>世界时间 / 天气</td><td>主要挂在主世界</td><td>下界末地无昼夜天空概念</td></tr><tr><td>出生点 / 重生</td><td>跨维度规则特殊</td><td>床只在 <code>bed_works=true</code> 的维度有效;下界用重生锚</td></tr></tbody></table><p>所以&quot;维度&quot;在存储层就是<strong>几套并列的世界目录</strong>,在运行层是<strong>几套并列的 <code>ServerLevel</code></strong>,各自独立 tick、独立加载区块(第 04/05 篇的那一整套机制,每个维度都跑一份)。它们之间没有共享的世界状态,<strong>唯一的桥就是把实体从一个 <code>ServerLevel</code> 搬到另一个</strong>——传送门、<code>/execute in</code>、末影珍珠落地,全都是这件事的不同触发方式。</p><hr><h2 id="串一下" tabindex="-1">串一下 <a class="header-anchor" href="#串一下" aria-label="Permalink to &quot;串一下&quot;">​</a></h2><p>把这一篇接回前面:维度类型是<strong>数据驱动的环境配置</strong>(第 11 篇动态注册表)、维度地形复用<strong>第 16 篇的世界生成管线</strong>、各维度<strong>独立 chunk 存储</strong>(第 07 篇)且<strong>各跑一套 tick/加载</strong>(第 04、05 篇)、末影龙是<strong>复杂实体</strong>(第 06 篇)。维度本身没有新机制,它只是把前面这些系统<strong>并列实例化几份</strong>,再用&quot;换算坐标 + 找门/建门&quot;这一小段传送逻辑把它们缝起来。</p><p>下界跑得快、传送门偶尔配错、末地一堆门——这三件看着神秘的事,拆开都只是 <code>coordinate_scale</code> 和 <code>PortalForcer</code> 的直接后果。</p>`,43)])])}const g=n(e,[["render",r]]);export{h as __pageData,g as default};
